// ============================================================
// LÓGICA: ¿Qué define un documento pendiente de procesar?
//
// La carpeta OUT_Separador funciona como cola de procesamiento.
// El servicio 'Interfaz Txt' toma los archivos, los procesa
// y los elimina/mueve automáticamente.
//
// → La MERA PRESENCIA de archivos en esta carpeta indica
//   que el servicio está detenido, colgado o con error.
//   No se requiere analizar contenido: cualquier archivo = pendiente.
// ============================================================

const archivos = $input.all();

// Filtrar entradas válidas (excluir '.' y '..' si el FTP los devuelve)
const archivosPendientes = archivos.filter(f =>
  f.json.name &&
  f.json.name !== '.' &&
  f.json.name !== '..'
);

const hayPendientes = archivosPendientes.length > 0;

// Calcular el más antiguo para evaluar urgencia
let archivoMasAntiguo = null;
let minutosEsperando  = 0;

if (hayPendientes) {
  const sorted = archivosPendientes.sort(
    (a, b) => new Date(a.json.modifyTime || 0) - new Date(b.json.modifyTime || 0)
  );
  archivoMasAntiguo = sorted[0].json;
  const ahora = new Date();
  const modTime = new Date(archivoMasAntiguo.modifyTime || ahora);
  minutosEsperando = Math.round((ahora - modTime) / 60000);
}

return [{
  json: {
    hayPendientes,
    cantidadPendientes: archivosPendientes.length,
    archivoMasAntiguo:  archivoMasAntiguo?.name || null,
    minutosEsperando,
    urgencia:           minutosEsperando > 60 ? 'ALTA' : minutosEsperando > 15 ? 'MEDIA' : 'BAJA',
    listaArchivos:      archivosPendientes.map(f => f.json.name),
    fechaRevision:      new Date().toISOString().split('T')[0],
    horaRevision:       new Date().toTimeString().split(' ')[0]
  }
}];
